        membership[i] = -1;

    new_centers_len = (int*) calloc(nclusters, sizeof(int));

    new_centers = (float**) malloc(nclusters * sizeof(float*));
    new_centers[0] = (float*) calloc(nclusters * nfeatures, sizeof(float));
    for (i = 1; i < nclusters; i)
        new_centers[i] = new_centers[i-1] + nfeatures;

    float *feature_device;
    float *clusters_device;
    int *membership_device;
    float *delta_device;
    int *partial_new_centers_len_device;
    float *partial_new_centers_device;
    float *new_centers_device;
    int *new_centers_len_device;

    cudaMalloc(&feature_device, npoints * nfeatures * sizeof(float));
    cudaMalloc(&clusters_device, nclusters * nfeatures * sizeof(float));
    cudaMalloc(&membership_device, npoints * sizeof(int));
    cudaMalloc(&delta_device, sizeof(float));
    cudaMalloc(&partial_new_centers_len_device, nclusters * sizeof(int));
    cudaMalloc(&partial_new_centers_device, nclusters * nfeatures * sizeof(float));
    cudaMalloc(&new_centers_device, nclusters * nfeatures * sizeof(float));
    cudaMalloc(&new_centers_len_device, nclusters * sizeof(int));

    float *feature_flat = (float*) malloc(npoints * nfeatures * sizeof(float));
    for (i = 0; i < npoints; i++) {
        for (j = 0; j < nfeatures; j++) {
            feature_flat[i * nfeatures + j] = feature[i][j];
        }
    }

    cudaMemcpy(feature_device, feature_flat, npoints * nfeatures * sizeof(float), cudaMemcpyHostToDevice);

    printf("num of threads = %d\n", nthreads);

    do {
        delta = 0.0;
        cudaMemset(delta_device, 0, sizeof(float));
        cudaMemset(partial_new_centers_len_device, 0, nclusters * sizeof(int));
        cudaMemset(partial_new_centers_device, 0, nclusters * nfeatures * sizeof(float));

        int blockSize = 256;
        int numBlocks = (npoints + blockSize - 1) / blockSize;

        find_nearest_point_kernel<<<numBlocks, blockSize>>>(feature_device, nfeatures,
            clusters_device, nclusters, npoints, membership_device,
            delta_device, partial_new_centers_len_device, partial_new_centers_device);

        cudaDeviceSynchronize();

        cudaMemcpy(new_centers_len, partial_new_centers_len_device, nclusters * sizeof(int), cudaMemcpyDeviceToHost);
        cudaMemcpy(new_centers[0], partial_new_centers_device, nclusters * nfeatures * sizeof(float), cudaMemcpyDeviceToHost);

        for (i = 0; i < nclusters; i++) {
            for (j = 0; j < nfeatures; j++) {
                if (new_centers_len[i] > 0)
                    clusters[i][j] = new_centers[i][j] / new_centers_len[i];
                new_centers[i][j] = 0.0;
            }
            new_centers_len[i] = 0;
        }

        cudaMemcpy(clusters_device, clusters[0], nclusters * nfeatures * sizeof(float), cudaMemcpyHostToDevice);

        cudaMemcpy(&delta, delta_device, sizeof(float), cudaMemcpyDeviceToHost);

    } while (delta > threshold && loop++ < 500);

    cudaFree(feature_device);
    cudaFree(clusters_device);
    cudaFree(membership_device);
    cudaFree(delta_device);
    cudaFree(partial_new_centers_len_device);
    cudaFree(partial_new_centers_device);
    cudaFree(new_centers_device);
